const processStep = (step: Step, state: ScenarioState): StepResult =>
  step.op === "quote" ? processQuote(step, state) : processClaim(step, state);

const quoteIndexAt = (steps: Step[], stepIndex: number): number =>
  steps.slice(0, stepIndex).filter((s) => s.op === "quote").length;

export const processScenario = (scenario: Scenario): ScenarioOutput => {
  const policies = new Map<number, Policy>();
  const results: StepResult[] = scenario.steps.map((step, stepIndex) =>
    processStep(step, {
      customer: scenario.customer,
      policies,
      quoteIndex: quoteIndexAt(scenario.steps, stepIndex),
      stepIndex,
    }),
  );
  return { results };
};

